import boto3
import json
import psycopg2
from functools import lru_cache

@lru_cache(maxsize=1)
def get_db_secret(secret_name: str) -> dict:
    """Fetch secret from AWS Secrets Manager with caching."""
    client = boto3.client("secretsmanager", region_name="us-east-1")
    response = client.get_secret_value(SecretId=secret_name)
    return json.loads(response["SecretString"])

def get_db_connection():
    secret = get_db_secret("prod/pipeline/postgres")
    return psycopg2.connect(
        host=secret["host"],
        port=secret["port"],
        user=secret["username"],
        password=secret["password"],
        dbname=secret["dbname"],
        sslmode="require"  # always enforce TLS
    )

from cryptography.fernet import Fernet
import base64
import os

class FieldEncryptor:
    """
    Encrypt individual sensitive fields before storing in a database.
    The key is fetched from a secrets manager, never hardcoded.
    """
    def __init__(self, key: bytes):
        self.fernet = Fernet(key)

    def encrypt(self, value: str) -> str:
        return self.fernet.encrypt(value.encode()).decode()

    def decrypt(self, token: str) -> str:
        return self.fernet.decrypt(token.encode()).decode()

