# Pattern: separate read/write connection pools with different credentials

import psycopg2
from contextlib import contextmanager

class PipelineDB:
    def __init__(self):
        self._read_secret = get_db_secret("prod/pipeline/postgres-readonly")
        self._write_secret = get_db_secret("prod/pipeline/postgres-writer")

    @contextmanager
    def read_connection(self):
        conn = psycopg2.connect(
            **self._read_secret,
            options="-c default_transaction_read_only=on"  # enforce at DB level too
        )
        try:
            yield conn
        finally:
            conn.close()

    @contextmanager
    def write_connection(self):
        conn = psycopg2.connect(**self._write_secret)
        try:
            yield conn
            conn.commit()
        except Exception:
            conn.rollback()
            raise
        finally:
            conn.close()

import time

def connect_with_retry(max_attempts: int = 3):
    for attempt in range(max_attempts):
        try:
            secret = get_db_secret("prod/pipeline/postgres")  # always re-fetch
            return psycopg2.connect(**secret)
        except psycopg2.OperationalError as e:
            if attempt == max_attempts - 1:
                raise
            time.sleep(2 ** attempt)
